void scheduler(void) {
	struct proc *tmp;
	struct cpu *c = mycpu();
	while (1) {
		int found = 0;
		intr_on();
		__enter_proc_cs
		tmp = __get_runnable_no_lock();
		if (NULL != tmp) {
			tmp->state = RUNNING;
			c->proc = tmp;
			w_satp(MAKE_SATP(tmp->pagetable));
			sfence_vma();
			swtch(&c->context, &tmp->context);
			w_satp(MAKE_SATP(kernel_pagetable));
			sfence_vma();
			if (ZOMBIE == tmp->state) {
				release(&(tmp->parent->lk));
			}
			found = 1;
		}
		c->proc = NULL;
		__leave_proc_cs
		if (!found) { intr_on(); asm volatile("wfi"); }
	}
}

void sched(void) {
	int intena;
	struct proc *p = myproc();
	if (r_sstatus_fs() == SSTATUS_FS_DIRTY) {
		((floattrap)floatstore)(p->trapframe);
		w_sstatus_fs(SSTATUS_FS_CLEAN);
	}
	p->proc_tms.stime += readtime() - p->ikstmp;
	intena = mycpu()->intena;
	swtch(&p->context, &mycpu()->context);
	mycpu()->intena = intena;
	p->ikstmp = readtime();
	((floattrap)floatload)(p->trapframe);
	w_sstatus_fs(SSTATUS_FS_CLEAN);
}

