int copyout(pagetable_t pagetable, uint64 dstva, char *src, uint64 len) {
	uint64 n, va0, pa0;
	while(len > 0){
		va0 = PGROUNDDOWN(dstva);
		pa0 = walkaddr(pagetable, va0);
		if(pa0 == NULL) return -1;
		n = PGSIZE - (dstva - va0);
		if(n > len) n = len;
		memmove((void *)(pa0 + (dstva - va0)), src, n);
		len -= n; src += n; dstva = va0 + PGSIZE;
	}
	return 0;
}

int copyout2(uint64 dstva, char *src, uint64 len) {
	struct proc *p = myproc();
	struct seg *s = partofseg(p->segment, dstva, dstva + len);
	if (s == NULL) return -1;
	uint64 badaddr = safememmove((char *)dstva, src, len, 1);
	return badaddr == 0 ? 0 : -1;
}

int copyin2(char *dst, uint64 srcva, uint64 len) {
	struct proc *p = myproc();
	struct seg *s = partofseg(p->segment, srcva, srcva + len);
	if (s == NULL) return -1;
	uint64 badaddr = safememmove(dst, (char *)srcva, len, 1);
	return badaddr == 0 ? 0 : -1;
}

static uint64 safememmove(char *dst, char *src, uint64 len, int srcinc) {
	struct proc * volatile p = myproc();
	uint64 volatile old = p->badaddr;
	uint64 safe_pc;
	asm volatile("auipc %0, 0x0" : "=r" (safe_pc));
	if (!save_point) { save_point = safe_pc; }
	uint64 badaddr = p->badaddr;
	if (badaddr == old) {
		permit_usr_mem();
		if (srcinc) { while (len--) { *dst++ = *src++; } }
		else { while (len--) { *dst++ = *src; } }
		badaddr = 0;
	} else { p->badaddr = old; }
	protect_usr_mem();
	return badaddr;
}

