int uvmcopy(pagetable_t old, pagetable_t new, uint64 start, uint64 end, int cow) {
    for (i = start; i < end; i += PGSIZE) {
        if ((pte = walk(old, i, 0)) == NULL || !(*pte & PTE_V)) continue;
        pa = PTE2PA(*pte);
        if (cow && (*pte & PTE_W)) {
