static int handle_store_page_fault_cow(pte_t *ptep) {
    pte_t pte = *ptep;
    uint64 pa = PTE2PA(pte);
    if (monopolizepage(pa)) {
        pte |= PTE_W;
    } else {
        char *copy = (char *)allocpage();
        memmove(copy, (char *)pa, PGSIZE);
        pagecopydone();
        pagereg((uint64)copy, 1);
        pte = PA2PTE(copy) | PTE_FLAGS(pte) | PTE_W;
    }
    pte &= ~PTE_COW;
    *ptep = pte;
    sfence_vma();
    return 0;
}

