int copyout(pagetable_t pagetable, uint64 dstva, char *src, uint64 len) {
  uint64 n, va0, pa0;
  while(len > 0){
    va0 = PGROUNDDOWN(dstva);
    pa0 = walkaddr(pagetable, va0);
    if(pa0 == NULL)
      return -1;
    n = PGSIZE - (dstva - va0);
    if(n > len) n = len;
    memmove((void *)(pa0 + (dstva - va0)), src, n);
    len -= n; src += n; dstva = va0 + PGSIZE;
  }
  return 0;
}

int copyout2(uint64 dstva, char *src, uint64 len) {
  struct proc *p = myproc();
  struct seg *s = partofseg(p->segment, dstva, dstva + len);
  if (s == NULL) return -1;
  uint64 badaddr = safememmove((char *)dstva, src, len, 1);
  return badaddr == 0 ? 0 : -1;
}

uint64 walkaddr(pagetable_t pagetable, uint64 va) {
  pte_t *pte; uint64 pa;
  if (va >= MAXUVA) return NULL;
  pte = walk(pagetable, va, 0);
  if(pte == 0) return NULL;
  if((*pte & PTE_V) == 0) return NULL;
  if((*pte & PTE_U) == 0) return NULL;
  pa = PTE2PA(*pte);
  return pa;
}

struct seg *partofseg(struct seg *head, uint64 start, uint64 end) {
  struct seg *s = locateseg(head, start);
  struct seg *s2 = locateseg(s, end - 1);
  if (s == NULL || s2 == NULL) return NULL;
  if (s != s2 && PGROUNDUP(s->addr + s->sz) != PGROUNDDOWN(s2->addr)) return NULL;
  return s;
}

