  struct proc * volatile p = myproc();
  uint64 volatile old = p->badaddr;
  uint64 safe_pc;
  asm volatile("auipc %0, 0x0" : "=r" (safe_pc));
  if (!save_point) { save_point = safe_pc; }
  uint64 badaddr = p->badaddr;
  if (badaddr == old) {
    permit_usr_mem();
    if (srcinc) { while (len--) { *dst++ = *src++; } }
    else { while (len --) { *dst++ = *src; } }
    badaddr = 0;
  } else { p->badaddr = old; }
  protect_usr_mem();
  return badaddr;
}

